import{_ as o,o as t,c as n,a2 as a}from"./chunks/framework.BYlK8ftn.js";const p=JSON.parse('{"title":"0002 — Babylon GLB import contract","description":"","frontmatter":{},"headers":[],"relativePath":"decisions/0002-glb-import-contract.md","filePath":"decisions/0002-glb-import-contract.md","lastUpdated":1781956454000}'),s={name:"decisions/0002-glb-import-contract.md"};function r(i,e,d,l,c,h){return t(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_0002-—-babylon-glb-import-contract" tabindex="-1">0002 — Babylon GLB import contract <a class="header-anchor" href="#_0002-—-babylon-glb-import-contract" aria-label="Permalink to &quot;0002 — Babylon GLB import contract&quot;">​</a></h1><ul><li>Status: Accepted</li><li>Date: 2026-06-20</li><li>Deciders: Daedalus (CTO)</li><li>Context issue: <a href="https://github.com/Fl0p/korovany" target="_blank" rel="noreferrer">FLO-257</a></li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>GLBs generated by the <code>meshy-3d</code> skill arrive at arbitrary scale, centering, and (occasionally) orientation. Dropping them into a scene raw produces models that are giant, off-origin, or sunk through the floor. We need one import path so every asset lands at a predictable size and position. ADR 0001 settled <em>where</em> assets live (<code>public/models/</code>, served as <code>/models/&lt;name&gt;.glb</code>); this ADR settles <em>how</em> they load.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>A single loader, <code>loadModel(scene, url, opts)</code> in <code>src/scenes/modelLoader.ts</code>:</p><ul><li><strong>Load path:</strong> <code>SceneLoader.ImportMeshAsync</code>, with <code>@babylonjs/loaders/glTF</code> imported for its side effect to register the GLB plugin. (<code>@babylonjs/loaders</code> added as a dependency.) Chosen over the looser <code>AppendSceneAsync</code> because we want the returned meshes back to parent and normalize them, not merge blindly into the scene.</li><li><strong>Normalization on import:</strong><ul><li>Re-parent the loaded top-level meshes under one <code>TransformNode</code> root.</li><li><strong>Scale:</strong> uniform, so the longest bounding-box extent equals <code>targetSize</code> (default <strong>2</strong> scene units). <code>fitScale()</code>.</li><li><strong>Position:</strong> recenter on the X/Z origin and, by default, <strong>ground</strong> the model so its lowest point sits at <code>y=0</code> (<code>groundIt: true</code>); set <code>false</code> to center on the origin instead. <code>recenterOffset()</code>.</li><li><strong>Orientation:</strong> none by default. glTF is right-handed / Y-up and the glTF loader already inserts its own handedness-conversion node, so re-flipping would double-correct. A <code>yaw</code> option (radians) is exposed for per-asset tweaks.</li></ul></li><li>Returns <code>{ root, meshes }</code>; callers position/parent the <code>root</code>, never the raw meshes.</li></ul><p>The scale/position math (<code>fitScale</code>, <code>recenterOffset</code>) is factored into pure functions with no engine state, unit-tested in <code>modelLoader.test.ts</code>.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>Assets are authored against a known convention (longest side ≈ 2 units, grounded), so camera framing and collision sizing are stable across models.</li><li><code>@babylonjs/loaders</code> adds to the bundle; the glTF loader is the only registered plugin (imported via the <code>/glTF</code> subpath, not the umbrella package) to keep the payload minimal.</li><li>The pure-math normalization is covered by unit tests; the full GLB load + on-screen result is a <strong>visual-truth</strong> check — verify in a browser with a real asset (the FLO-256 treasure-chest sample) before wiring a model into a shipped scene. The current <code>MainScene</code> rotating cube is unchanged; wiring a loaded model into a scene is follow-up work.</li></ul>',10)])])}const g=o(s,[["render",r]]);export{p as __pageData,g as default};
